export function script(input) {
  const responses = Array.isArray(input.httpResponses) ? input.httpResponses : [];
  const liveUrls = responses.map((item) => item?.url || item?.finalUrl || item?.input).filter((value) => typeof value === 'string' && value.length > 0);
  const tlsTargets = liveUrls.filter((url) => url.startsWith('https://')).map((url) => { try { const parsed = new URL(url); return `${parsed.hostname}:${parsed.port || '443'}`; } catch { return null; } }).filter((value) => typeof value === 'string' && value.length > 0);
  return { liveUrls: Array.from(new Set(liveUrls)), tlsTargets: Array.from(new Set(tlsTargets)) };
}

export function script(input) {
  const asList = (value) => Array.isArray(value) ? value.map((item) => String(item || '').trim()).filter(Boolean) : [];
  const normalizePath = (value) => {
    const text = String(value || '').trim();
    if (!text) return '';
    try {
      const parsed = new URL(text);
      return parsed.pathname || '/';
    } catch {
      const pathOnly = text.split(/[?#]/)[0] || '/';
      return pathOnly.startsWith('/') ? pathOnly : `/${pathOnly}`;
    }
  };
  const outOfScopePaths = Array.from(new Set(asList(input.outOfScopePaths).map(normalizePath).filter(Boolean)));
  const isOutOfScope = (value) => {
    const path = normalizePath(value);
    return outOfScopePaths.some((scopePath) => path === scopePath || path.startsWith(scopePath.endsWith('/') ? scopePath : `${scopePath}/`));
  };
  const requestedIntensity = String(input.scanIntensity || 'safe').trim().toLowerCase();
  const intensity = ['safe', 'normal', 'thorough'].includes(requestedIntensity) ? requestedIntensity : 'safe';
  const targetLimit = { safe: 10, normal: 30, thorough: 75 }[intensity];
  const liveUrls = Array.from(new Set(asList(input.liveUrls)));
  const scopedLiveUrls = [];
  let excludedByScope = 0;
  let eligibleTargets = 0;
  for (const url of liveUrls) {
    if (isOutOfScope(url)) {
      excludedByScope++;
      continue;
    }
    eligibleTargets++;
    if (scopedLiveUrls.length < targetLimit) scopedLiveUrls.push(url);
  }
  return {
    scopedLiveUrls,
    scanProfile: {
      intensity,
      targetLimit,
      originalTargets: liveUrls.length,
      eligibleTargets,
      scopedTargets: scopedLiveUrls.length,
      excludedByScope,
      truncatedByIntensity: Math.max(0, eligibleTargets - scopedLiveUrls.length),
      outOfScopePaths,
    },
  };
}

export function script(input) {
