  const nucleiFindings = Array.isArray(input.nucleiFindings) ? input.nucleiFindings : [];
  const tlsFindings = Array.isArray(input.tlsFindings) ? input.tlsFindings : [];
  const scanProfile = input.scanProfile && typeof input.scanProfile === 'object' ? input.scanProfile : {};
  const outOfScopePaths = Array.isArray(scanProfile.outOfScopePaths) ? scanProfile.outOfScopePaths.map((item) => String(item || '').trim()).filter(Boolean) : [];
  const normalizePath = (value) => {
    const text = String(value || '').trim();
    if (!text) return '';
    try {
      const parsed = new URL(text);
      return parsed.pathname || '/';
    } catch {
      const pathOnly = text.split(/[?#]/)[0] || '/';
      return pathOnly.startsWith('/') ? pathOnly : `/${pathOnly}`;
    }
  };
  const isOutOfScope = (value) => {
    const path = normalizePath(value);
    return outOfScopePaths.some((scopePath) => path === scopePath || path.startsWith(scopePath.endsWith('/') ? scopePath : `${scopePath}/`));
  };
  const findingTarget = (item) => item?.matchedAt || item?.url || item?.host || item?.target || item?.input || '';
  const scopedEndpoints = endpoints.filter((url) => !isOutOfScope(url));
  const scopedNucleiFindings = nucleiFindings.filter((item) => !isOutOfScope(findingTarget(item)));
  const excludedFromReport = (endpoints.length - scopedEndpoints.length) + (nucleiFindings.length - scopedNucleiFindings.length);
  const quickWins = scopedNucleiFindings.filter((item) => ['medium', 'high', 'critical'].includes(String(item?.severity || '').toLowerCase())).map((item) => ({ source: 'nuclei', templateId: item.templateId, name: item.name, severity: item.severity, matchedAt: item.matchedAt }));
  return { report: { summary: { liveAssets: httpResponses.length, crawledEndpoints: scopedEndpoints.length, nucleiFindings: scopedNucleiFindings.length, tlsFindings: tlsFindings.length, quickWins: quickWins.length, scanIntensity: scanProfile.intensity || 'safe', scopedTargets: scanProfile.scopedTargets || 0, targetLimit: scanProfile.targetLimit || null, excludedByScope: Number(scanProfile.excludedByScope || 0) + excludedFromReport }, scope: { outOfScopePaths, originalTargets: scanProfile.originalTargets || 0, eligibleTargets: scanProfile.eligibleTargets || 0, truncatedByIntensity: scanProfile.truncatedByIntensity || 0 }, quickWins: quickWins.slice(0, 100), needsReview: scopedNucleiFindings.slice(0, 100), tlsFindings: tlsFindings.slice(0, 50), interestingEndpoints: scopedEndpoints.filter((url) => /admin|debug|api|graphql|swagger|login|backup/i.test(url)).slice(0, 100), nextSteps: ['Validate findings manually before submitting reports', 'Confirm each lead is in scope', 'Avoid destructive checks and respect program rate limits'] } };
}
